#!/bin/bash
# train/scripts/download_datasets.sh — Kick off all dataset downloads.
#
# Run AFTER the external SSD is mounted and train/setup.sh has been run.
# All three main downloads run in parallel in background terminals.
# WikiArt and warmstart weights can be downloaded to internal storage now.
#
# Usage:
#   source train/.venv/bin/activate
#   bash train/scripts/download_datasets.sh \
#     --ssd /Volumes/IrisData \
#     --laion laion_filtered.parquet
#
# Required: laion_filtered.parquet generated by scripts/prepare_laion.py

set -e

SSD_ROOT="/Volumes/IrisData"
LAION_PARQUET="laion_filtered.parquet"
INTERNAL_STAGING="$HOME/iris_data_staging"

while [[ $# -gt 0 ]]; do
    case $1 in
        --ssd)   SSD_ROOT="$2"; shift 2 ;;
        --laion) LAION_PARQUET="$2"; shift 2 ;;
        *) echo "Unknown arg: $1"; exit 1 ;;
    esac
done

# ── Verify external SSD is mounted ──────────────────────────────────────────
if [ ! -d "$SSD_ROOT" ]; then
    echo "Error: SSD not found at $SSD_ROOT"
    echo "Mount the drive first, then re-run."
    exit 1
fi

# ── Verify filtered LAION parquet exists ─────────────────────────────────────
if [ ! -f "$LAION_PARQUET" ]; then
    echo "Error: LAION parquet not found: $LAION_PARQUET"
    echo "Run: python train/scripts/prepare_laion.py --output $LAION_PARQUET"
    exit 1
fi

# ── Create directory structure on external SSD ───────────────────────────────
echo "Creating directory structure on $SSD_ROOT ..."
mkdir -p "$SSD_ROOT/raw/laion"
mkdir -p "$SSD_ROOT/raw/journeydb"
mkdir -p "$SSD_ROOT/raw/coyo"
mkdir -p "$SSD_ROOT/raw/wikiart"
mkdir -p "$SSD_ROOT/shards"
mkdir -p "$SSD_ROOT/precomputed/qwen3"
mkdir -p "$SSD_ROOT/precomputed/vae"
mkdir -p "$SSD_ROOT/precomputed/siglip"
mkdir -p "$SSD_ROOT/checkpoints"
mkdir -p "$SSD_ROOT/weights"

mkdir -p "$INTERNAL_STAGING"

echo ""
echo "========================================================================"
echo "  Download plan — run each block in a separate terminal"
echo "========================================================================"

# ── WikiArt (tiny, run now) ───────────────────────────────────────────────────
echo ""
echo "── WikiArt (1.7 GB, fast) ──────────────────────────────────────────────"
echo "Run:"
echo "  huggingface-cli download Artificio/WikiArt \\"
echo "    --repo-type dataset \\"
echo "    --local-dir $SSD_ROOT/raw/wikiart"
echo "  # Prepend style label to captions: 'An impressionist painting showing {caption}'"

# ── Warmstart weights (5.3 GB, run now on internal) ─────────────────────────
echo ""
echo "── IP-Adapter warmstart weights (5.3 GB) ──────────────────────────────"
echo "Run (saves to internal staging, not SSD):"
echo "  huggingface-cli download InstantX/FLUX.1-dev-IP-Adapter \\"
echo "    --local-dir $INTERNAL_STAGING/flux_dev_ipadapter"
echo "  # Only image_proj.* keys transfer to Klein 4B (Perceiver Resampler warmstart)"

# ── Terminal 1: LAION-Aesthetics (largest, ~150 GB) ──────────────────────────
echo ""
echo "── TERMINAL 1: LAION-Aesthetics-v2 (~150 GB) ──────────────────────────"
echo "Run under caffeinate:"
cat <<'LAION'
  # Detect performance cores (M1 Max = 8; never hardcode)
  PERF_CORES=$(sysctl -n hw.perflevel0.logicalcpu 2>/dev/null || nproc)
  IO_THREADS=$((PERF_CORES * 2))

  caffeinate -i -d \
  img2dataset \
    --url_list laion_filtered.parquet \
    --input_format parquet \
    --url_col url \
    --caption_col caption \
    --output_format webdataset \
    --output_folder /Volumes/IrisData/raw/laion \
    --image_size 512 \
    --resize_only_if_bigger True \
    --resize_mode keep_ratio_largest \
    --encode_format jpg \
    --encode_quality 85 \
    --processes_count $PERF_CORES \
    --thread_count $IO_THREADS \
    --save_additional_columns '["aesthetic"]' \
    2>&1 | tee logs/laion_download.log
LAION

# ── Terminal 2: JourneyDB (~80 GB) ───────────────────────────────────────────
echo ""
echo "── TERMINAL 2: JourneyDB (~80 GB, non-commercial research) ────────────"
cat <<'JDB'
  caffeinate -i -d \
  huggingface-cli download JourneyDB/JourneyDB \
    --repo-type dataset \
    --local-dir /Volumes/IrisData/raw/journeydb \
    2>&1 | tee logs/journeydb_download.log
JDB

# ── Terminal 3: COYO filtered (~25 GB) ──────────────────────────────────────
echo ""
echo "── TERMINAL 3: COYO filtered (~25 GB) ─────────────────────────────────"
echo "Note: prepare COYO parquet first — see scripts/prepare_coyo.py"
cat <<'COYO'
  PERF_CORES=$(sysctl -n hw.perflevel0.logicalcpu 2>/dev/null || nproc)
  IO_THREADS=$((PERF_CORES * 2))

  caffeinate -i -d \
  img2dataset \
    --url_list coyo_filtered.parquet \
    --input_format parquet \
    --url_col url \
    --caption_col caption \
    --output_format webdataset \
    --output_folder /Volumes/IrisData/raw/coyo \
    --image_size 512 \
    --resize_only_if_bigger True \
    --resize_mode keep_ratio_largest \
    --encode_format jpg \
    --encode_quality 85 \
    --processes_count $PERF_CORES \
    --thread_count $IO_THREADS \
    2>&1 | tee logs/coyo_download.log
COYO

echo ""
echo "========================================================================"
echo "  After all downloads complete, run:"
echo "    python train/scripts/build_shards.py --ssd $SSD_ROOT"
echo "========================================================================"

mkdir -p logs
echo ""
echo "Hint: TB4 health check (run in background during downloads):"
cat <<HEALTH
  while true; do
    if [ ! -d "$SSD_ROOT" ]; then
      echo "\$(date): TB4 drive unmounted" | tee -a logs/health.log
    fi
    sleep 300
  done &
HEALTH
